    9:{nombre:'LA MAESTRIA',etapa:'Cierre — Servicio',desc:'Graduacion almica. Integracion de sabiduria acumulada. Cierre de memorias de linaje. Fin de etapa definitivo y apertura de nuevo ciclo.'},
