export const pdfI18n: Record<PdfLang, PdfT> = { es, en, fr };

export function getPdfLang(): PdfLang {
  try {
    const saved = localStorage.getItem('mecf-lang') as PdfLang;
    return ['es','en','fr'].includes(saved) ? saved : 'es';
  } catch {
    return 'es';
  }
}

export function interp(s: string, vars: Record<string, string>): string {
  return s.replace(/\{(\w+)\}/g, (_, k) => vars[k] ?? k);
}
